        if (call.name === 'write_to_file' && call.args && call.args.CodeContent) {
          const content = call.args.CodeContent;
          // Check if it contains the Manifesto function or similar
          if (content.includes('function Manifesto') || content.includes('function Faq')) {
            console.log(`Found candidate at step ${data.step_index}`);
