            console.log("Written restored content to scratch/restored-chunk.txt");
            process.exit(0);
          }
        }
      }
    }
  } catch (e) {
    // Ignore invalid JSON lines
  }
}

console.log("No candidates found containing Manifesto or Faq definition.");
